def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    max_bin = np.max(bins) if len(bins) > 0 else 1
    min_bin = np.min(bins[bins > 0]) if np.any(bins > 0) else 1
    for i in range(len(bins)):
        b = bins[i]
        if b == 0:
            priorities[i] = float('inf')
            continue
        ratio = item / b
        base_score = 0
        for threshold, multiplier in [(0.9, 100), (0.75, 70), (0.5, 40), (0.25, 20)]:
            if ratio > threshold:
                base_score += multiplier * ratio
                break
        else:
            base_score += 5 * ratio
        if b < min_bin * 1.5:
            base_score += 10
        elif b > max_bin * 0.75:
            base_score -= 10
        penalty = 0
        if ratio > 1:
            penalty = 500 * (ratio - 1)**3
        usage_factor = 1.0
        for j in range(len(bins)):
            if i != j and bins[j] > 0:
                diff = abs(b - bins[j])
                usage_factor += (diff / max_bin) * 0.1
        score = base_score * usage_factor + penalty
        if i % 3 == 0:
            score *= 1.2
        elif i % 3 == 1:
            score *= 0.85
        else:
            score *= 1.0
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if len(finite_priorities) > 0:
        min_priority = np.min(finite_priorities)
    else:
        min_priority = 0
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = min_priority + 150
    sorted_indices = np.argsort(priorities)
    for rank, idx in enumerate(sorted_indices):
        adjustment = (len(priorities) - rank) * 0.05
        priorities[idx] += adjustment
    return priorities
